<template>
  <div class="results-container">
    <h2>
      {{ phase === "qualification" ? "Qualification" : "Division" }} Results
    </h2>

    <div v-if="loading" class="loading-container">
      <div class="loading-spinner"></div>
      <p>Loading match results...</p>
    </div>

    <div v-else-if="error" class="error-container">
      <i class="error-icon">!</i>
      <p>{{ error }}</p>
    </div>

    <div v-else>
      <div v-if="groupedMatches.length > 0" class="results-list">
        <div
          v-for="(group, index) in groupedMatches"
          :key="index"
          class="result-group"
        >
          <div class="date-header">
            <h3>{{ formatDateHeader(group.date) }}</h3>
            <span class="match-count"
              >{{ group.matches.length }}
              {{ group.matches.length === 1 ? "match" : "matches" }}</span
            >
          </div>

          <div class="result-table">
            <table>
              <thead>
                <tr v-if="$props.isAdmin">
                  <th class="team1-column"></th>
                  <th class="score-column"></th>
                  <th class="team2-column"></th>
                  <th class="actions-header">Actions</th>
                </tr>
              </thead>
              <tbody>
                <tr
                  v-for="match in group.matches"
                  :key="match.id"
                  class="result-row"
                >
                  <td class="match-team home-team">
                    {{ match.homeTeam }}
                  </td>
                  <td class="match-score score-column">
                    <span
                      :class="{
                        winner: match.homeTeamScore > match.awayTeamScore,
                      }"
                    >
                      {{ match.homeTeamScore }}
                    </span>
                    -
                    <span
                      :class="{
                        winner: match.awayTeamScore > match.homeTeamScore,
                      }"
                    >
                      {{ match.awayTeamScore }}
                    </span>
                  </td>
                  <td class="match-team away-team">
                    {{ match.awayTeam }}
                  </td>
                  <td v-if="$props.isAdmin" class="row-actions">
                    <div class="action-buttons">
                      <button
                        @click="editMatchResult(match)"
                        class="row-btn edit-btn"
                      >
                        Edit
                      </button>
                      <button
                        @click="confirmDelete(match)"
                        class="row-btn delete-btn"
                      >
                        Delete
                      </button>
                    </div>
                  </td>
                </tr>
              </tbody>
            </table>
          </div>
        </div>
      </div>

      <div v-else class="no-results">
        <p>
          No
          {{ phase === "qualification" ? "qualification" : "division" }} match
          results found
        </p>
      </div>

      <!-- <p class="last-updated">Last updated: {{ lastUpdated }}</p> -->
    </div>

    <!-- Edit Match Result Modal -->
    <div v-if="showEditModal" class="modal-overlay">
      <div class="modal-content">
        <div class="modal-header">
          <h3>Edit Match Result</h3>
          <button @click="showEditModal = false" class="close-btn">×</button>
        </div>
        <div class="modal-body">
          <div class="match-teams-header">
            {{ editingMatch.homeTeam }} vs {{ editingMatch.awayTeam }}
          </div>

          <div class="form-row">
            <div class="form-group">
              <label :for="`home-team-score-${editingMatch.id}`"
                >{{ editingMatch.homeTeam }} Score:</label
              >
              <input
                :id="`home-team-score-${editingMatch.id}`"
                type="number"
                min="0"
                v-model.number="editingMatch.homeTeamScore"
              />
            </div>
            <div class="form-group">
              <label :for="`away-team-score-${editingMatch.id}`"
                >{{ editingMatch.awayTeam }} Score:</label
              >
              <input
                :id="`away-team-score-${editingMatch.id}`"
                type="number"
                min="0"
                v-model.number="editingMatch.awayTeamScore"
              />
            </div>
          </div>
          <div class="form-row">
            <div class="form-group">
              <label :for="`match-date-${editingMatch.id}`">Date:</label>
              <input
                :id="`match-date-${editingMatch.id}`"
                type="date"
                v-model="editingMatch.dateString"
              />
            </div>
          </div>
        </div>
        <div class="modal-footer">
          <button @click="updateMatchResult" class="btn save-btn">
            Save Changes
          </button>
          <button @click="showEditModal = false" class="btn cancel-btn">
            Cancel
          </button>
        </div>
      </div>
    </div>

    <!-- Delete Confirmation Modal -->
    <div v-if="showDeleteModal" class="modal-overlay">
      <div class="modal-content">
        <div class="modal-header">
          <h3>Confirm Delete</h3>
          <button @click="showDeleteModal = false" class="close-btn">×</button>
        </div>
        <div class="modal-body">
          <p>Are you sure you want to delete this match result?</p>
          <div class="match-info">
            <strong
              >{{ matchToDelete.homeTeam }} vs
              {{ matchToDelete.awayTeam }}</strong
            >
            <br />
            <span>{{ formatDate(matchToDelete.date) }}</span>
          </div>
          <p class="warning">This action cannot be undone.</p>
        </div>
        <div class="modal-footer">
          <button @click="deleteMatchResult" class="btn delete-btn">
            Delete
          </button>
          <button @click="showDeleteModal = false" class="btn cancel-btn">
            Cancel
          </button>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import { ref, computed, onMounted, reactive, watch } from "vue";
import {
  collection,
  getDocs,
  doc,
  updateDoc,
  query,
  where,
  // orderBy,
} from "firebase/firestore";
import { db } from "@/firebase";

export default {
  name: "MatchResults",

  props: {
    isAdmin: {
      type: Boolean,
      default: false,
    },
    phase: {
      type: String,
      default: "qualification",
      validator: (value) => ["qualification", "division"].includes(value),
    },
  },

  setup(props) {
    const matches = ref([]);
    const loading = ref(true);
    const error = ref(null);
    const lastUpdated = ref(null);

    // Modals
    const showEditModal = ref(false);
    const showDeleteModal = ref(false);

    const editingMatch = reactive({
      id: "",
      homeTeam: "",
      awayTeam: "",
      homeTeamScore: 0,
      awayTeamScore: 0,
      date: null,
      dateString: "",
    });

    const matchToDelete = reactive({
      id: "",
      homeTeam: "",
      awayTeam: "",
      date: null,
    });

    // Format date to user-friendly string
    const formatDate = (dateString) => {
      const date = new Date(dateString);
      return date.toLocaleDateString("en-US", {
        weekday: "short",
        month: "short",
        day: "numeric",
      });
    };

    // Format date for header - fixed to show actual date instead of today/yesterday
    const formatDateHeader = (dateString) => {
      const date = new Date(dateString);
      return date.toLocaleDateString("en-US", {
        weekday: "long",
        month: "long",
        day: "numeric",
        year: "numeric",
      });
    };

    // Filter for completed matches based on phase
    const filteredMatches = computed(() => {
      return matches.value.filter(
        (match) => match.phase === props.phase && match.isCompleted === true
      );
    });

    // Group matches by date - using completedDate for proper grouping
    const groupedMatches = computed(() => {
      const groups = [];
      const dateMap = {};

      // Sort matches by date (kept for consistency)
      const sortedMatches = [...filteredMatches.value].sort((a, b) => {
        // Use the original match date for sorting
        const dateA = new Date(a.date);
        const dateB = new Date(b.date);
        return dateB - dateA; // Newest first
      });

      // Group by the original match date
      sortedMatches.forEach((match) => {
        // Use the ORIGINAL match date for grouping, not completedDate
        const matchDate = new Date(match.date);
        // Use only the date part for grouping (ignore time)
        const dateString = matchDate.toISOString().split("T")[0];

        if (!dateMap[dateString]) {
          dateMap[dateString] = {
            date: matchDate,
            matches: [],
          };
          groups.push(dateMap[dateString]);
        }

        dateMap[dateString].matches.push(match);
      });

      return groups;
    });

    // Load matches data on component mount
    const loadData = async () => {
      try {
        loading.value = true;
        console.log(`Loading results for ${props.phase} phase`);

        // SIMPLIFIED QUERY WITHOUT ORDERBY - to debug the issue
        const matchesQuery = query(
          collection(db, "matches"),
          where("phase", "==", props.phase),
          where("isCompleted", "==", true)
        );

        const querySnapshot = await getDocs(matchesQuery);
        matches.value = [];

        console.log(
          `Found ${querySnapshot.size} completed matches for phase ${props.phase}`
        );

        querySnapshot.forEach((doc) => {
          const matchData = doc.data();

          // Convert Firestore timestamp to JS Date if needed
          const date = matchData.date?.toDate
            ? matchData.date.toDate()
            : new Date(matchData.date);

          const completedDate = matchData.completedDate?.toDate
            ? matchData.completedDate.toDate()
            : matchData.completedDate
            ? new Date(matchData.completedDate)
            : date; // Fallback to match date if no completed date

          matches.value.push({
            id: doc.id,
            ...matchData,
            // Ensure consistent field names
            homeTeam: matchData.homeTeam || matchData.player1,
            awayTeam: matchData.awayTeam || matchData.player2,
            homeTeamScore: matchData.homeTeamScore || 0,
            awayTeamScore: matchData.awayTeamScore || 0,
            date: date,
            completedDate: completedDate || date, // Ensure there's always a completedDate
          });
        });

        lastUpdated.value = new Date().toLocaleString();
        loading.value = false;
      } catch (err) {
        console.error("Error loading match results:", err);
        error.value = `Failed to load ${props.phase} match results. Please try again later.`;
        loading.value = false;
      }
    };

    // Edit match result
    const editMatchResult = (match) => {
      const matchDate = new Date(match.completedDate || match.date);

      // Clone the match data to avoid directly modifying the reactive object
      editingMatch.id = match.id;
      editingMatch.homeTeam = match.homeTeam;
      editingMatch.awayTeam = match.awayTeam;
      editingMatch.homeTeamScore = match.homeTeamScore || 0;
      editingMatch.awayTeamScore = match.awayTeamScore || 0;
      editingMatch.date = matchDate;
      editingMatch.dateString = matchDate.toISOString().split("T")[0];

      showEditModal.value = true;
    };

    // Update match result
    const updateMatchResult = async () => {
      try {
        const matchRef = doc(db, "matches", editingMatch.id);

        // Create a new date object from the date string
        const newDate = new Date(editingMatch.dateString);

        await updateDoc(matchRef, {
          homeTeamScore: editingMatch.homeTeamScore,
          awayTeamScore: editingMatch.awayTeamScore,
          team1Score: editingMatch.homeTeamScore,
          team2Score: editingMatch.awayTeamScore,
          completedDate: newDate, // Update the completedDate for proper grouping
        });

        // Reload matches data
        await loadData();

        showEditModal.value = false;
      } catch (error) {
        console.error("Error updating match result:", error);
        alert("Failed to update match result. Please try again.");
      }
    };

    // Confirm delete
    const confirmDelete = (match) => {
      matchToDelete.id = match.id;
      matchToDelete.homeTeam = match.homeTeam;
      matchToDelete.awayTeam = match.awayTeam;
      matchToDelete.date = match.completedDate || match.date;

      showDeleteModal.value = true;
    };

    // Delete match result
    const deleteMatchResult = async () => {
      try {
        // Instead of a true delete, we can also mark it as not completed
        const matchRef = doc(db, "matches", matchToDelete.id);
        await updateDoc(matchRef, {
          isCompleted: false,
          completedDate: null,
          homeTeamScore: null,
          awayTeamScore: null,
          team1Score: null,
          team2Score: null,
        });

        // Reload matches data
        await loadData();

        showDeleteModal.value = false;
      } catch (error) {
        console.error("Error deleting match result:", error);
        alert("Failed to delete match result. Please try again.");
      }
    };

    // Watch for changes to the phase prop and reload data when it changes
    watch(
      () => props.phase,
      (newPhase) => {
        console.log(`Phase changed to: ${newPhase}`);
        loadData();
      }
    );

    // Initialize component
    onMounted(() => {
      loadData();
    });

    return {
      matches,
      filteredMatches,
      groupedMatches,
      loading,
      error,
      lastUpdated,
      formatDate,
      formatDateHeader,
      showEditModal,
      showDeleteModal,
      editingMatch,
      matchToDelete,
      editMatchResult,
      updateMatchResult,
      confirmDelete,
      deleteMatchResult,
    };
  },
};
</script>

